query:
-- Índices para transactions: consultas por usuário+data (listagem, relatórios, dashboard)
CREATE INDEX IF NOT EXISTS idx_transactions_user_date
  ON transactions (userId, date);

-- Índice para transactions por usuário+tipo (filtros de receita/despesa)
CREATE INDEX IF NOT EXISTS idx_transactions_user_type
  ON transactions (userId, type);

-- Índice para transactions por usuário+categoria (relatórios por categoria)
CREATE INDEX IF NOT EXISTS idx_transactions_user_category
  ON transactions (userId, categoryId);

-- Índice para categories por usuário (listagem de categorias)
CREATE INDEX IF NOT EXISTS idx_categories_user
  ON categories (userId);

-- Índice para recurring_transactions por usuário+ativo (geração automática)
CREATE INDEX IF NOT EXISTS idx_recurring_user_active
  ON recurring_transactions (userId, active);

